"use client";

import React from "react";

type LanguageSwitcherProps = {
  currentLanguage: string;
  onSwitch: (lang: string) => void;
};

export default function LanguageSwitcher({
  currentLanguage,
  onSwitch,
}: LanguageSwitcherProps) {
  return (
    <div style={{ position: "absolute", left: 10, top: 10 }}>
      <button
        style={{
          marginRight: "8px",
          backgroundColor: currentLanguage === "es" ? "#ccc" : "#fff",
        }}
        onClick={() => onSwitch("es")}
      >
        ES
      </button>
      <button
        style={{
          backgroundColor: currentLanguage === "en" ? "#ccc" : "#fff",
        }}
        onClick={() => onSwitch("en")}
      >
        EN
      </button>
    </div>
  );
}
