"use client";

import React, { useState } from "react";
import LanguageSwitcher from "./components/LanguageSwitcher";

export default function Home() {
  const [language, setLanguage] = useState("es");

  const handleLanguageSwitch = (lang: string) => {
    setLanguage(lang);
  };

  return (
    <div>
      {/* Botones de idioma en la parte izquierda */}
      <LanguageSwitcher currentLanguage={language} onSwitch={handleLanguageSwitch} />

      {/* Encima del título de bienvenida: login/register */}
      <div style={{ textAlign: "center", marginTop: "2rem" }}>
        <LoginRegisterButtons />
      </div>

      {/* Sección principal (Hero) */}
      <section className="hero" style={{ textAlign: "center", marginTop: "2rem" }}>
        <h1 className="hero-title">
          {language === "es" ? "Bienvenido a mi sitio web" : "Welcome to my website"}
        </h1>
        <p className="hero-subtitle">|||</p>
      </section>

      {/* Aquí continuarías con tu resto de contenido (CV, Slider, ChatBot, etc.) */}
    </div>
  );
}
